var doc = uiapp.ActiveUIDocument.Document;
var view = uiapp.ActiveUIDocument.ActiveView;
var elsInView = new FilteredElementCollector(doc, view.Id).WhereElementIsNotElementType().ToList();
var cats = elsInView.Select(e => e.Category?.Name ?? "<none>").GroupBy(c => c).Select(g => new { category = g.Key, count = g.Count() }).OrderByDescending(x => x.count).ToList();
return new { view_name = view.Name, total_visible_elements = elsInView.Count, categories = cats };
